import vex
from llama_stack_client import LlamaStackMemory

memory = LlamaStackMemory()

vex_policy = vex.Policy({
    'name': 'privilege-protection',
    'rules': [
        {'type': 'pii_detection', 'fields': ['ssn', 'client_name']},
        {'type': 'keyword_block', 'patterns': ['attorney_client_privileged']}
    ]
})

@vex.verify(policies=['privilege-protection'])
def safe_memory_retrieval(query):
    docs = memory.retrieve(query)
    return {'documents': docs, 'safe': True}

client_query = "Retrieve Smith's merger docs"
approved_docs = safe_memory_retrieval(client_query)

import vex
import json

from llama_stack_client import LlamaStackTools

tools = LlamaStackTools()

EDISCOVERY_SCHEMA = {
    'type': 'object',
    'properties': {
        'doc_id': {'type': 'string'},
        'relevance_score': {'type': 'number', 'minimum': 0, 'maximum': 1},
        'privilege_status': {'type': 'string', 'enum': ['privileged', 'non_privileged']}
    },
    'required': ['doc_id', 'relevance_score', 'privilege_status']
}

@vex.verify(policies=['json_schema_validation'], schema=EDISCOVERY_SCHEMA)
def validate_ediscovery_results(tool_input):
    return tools.classify_documents(tool_input)

batch = [{'path': '/cases/smith_merger.pdf'}]
validated_results = validate_ediscovery_results(batch)

assert all('relevance_score' in doc for doc in validated_results)
